import React, { useEffect, useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import Logo from './Logo';

const Hero: React.FC = () => {
  const [isLoading, setIsLoading] = useState(true);
  const [mousePosition, setMousePosition] = useState({ x: 0, y: 0 });

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      setMousePosition({ x: e.clientX, y: e.clientY });
    };
    window.addEventListener('mousemove', handleMouseMove);
    
    const timer = setTimeout(() => setIsLoading(false), 2000);
    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      clearTimeout(timer);
    };
  }, []);

  return (
    <>
      {/* Loading Screen */}
      <AnimatePresence>
        {isLoading && (
          <motion.div
            className="fixed inset-0 z-50 bg-gradient-to-br from-[#5b3e31] to-black flex items-center justify-center overflow-hidden"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ 
              opacity: 0,
              y: "-100vh",
              transition: { duration: 1.5, ease: "easeInOut" }
            }}
          >
            {/* House Shape Container */}
            <motion.div
              className="relative"
              initial={{ scale: 0, rotate: -180 }}
              animate={{ 
                scale: [0, 1.2, 1],
                rotate: [-180, 360, 0],
                transition: { duration: 1.5, ease: "easeInOut" }
              }}
              exit={{ 
                scale: 0.8,
                rotate: 180,
                transition: { duration: 1, ease: "easeInOut" }
              }}
            >
              {/* House SVG Shape */}
              <motion.svg
                width="300"
                height="300"
                viewBox="0 0 300 300"
                className="relative z-10"
                initial={{ pathLength: 0 }}
                animate={{ pathLength: 1 }}
                transition={{ duration: 2, delay: 0.5 }}
              >
                {/* Roof */}
                <motion.path
                  d="M150 50 L250 150 L50 150 Z"
                  fill="rgba(255, 255, 255, 0.9)"
                  stroke="#ffffff"
                  strokeWidth="3"
                  initial={{ opacity: 0 }}
                  animate={{ opacity: 1 }}
                  transition={{ duration: 0.5, delay: 1 }}
                />
                
                {/* House Body */}
                <motion.rect
                  x="70"
                  y="150"
                  width="160"
                  height="120"
                  fill="rgba(255, 255, 255, 0.9)"
                  stroke="#ffffff"
                  strokeWidth="3"
                  initial={{ opacity: 0 }}
                  animate={{ opacity: 1 }}
                  transition={{ duration: 0.5, delay: 1.2 }}
                />
                
                {/* Door */}
                <motion.rect
                  x="130"
                  y="190"
                  width="40"
                  height="80"
                  fill="#5b3e31"
                  stroke="#ffffff"
                  strokeWidth="2"
                  initial={{ opacity: 0 }}
                  animate={{ opacity: 1 }}
                  transition={{ duration: 0.5, delay: 1.4 }}
                />
                
                {/* Windows */}
                <motion.rect
                  x="90"
                  y="170"
                  width="30"
                  height="30"
                  fill="#ffffff"
                  stroke="#5b3e31"
                  strokeWidth="2"
                  initial={{ opacity: 0 }}
                  animate={{ opacity: 1 }}
                  transition={{ duration: 0.5, delay: 1.6 }}
                />
                
                <motion.rect
                  x="180"
                  y="170"
                  width="30"
                  height="30"
                  fill="#ffffff"
                  stroke="#5b3e31"
                  strokeWidth="2"
                  initial={{ opacity: 0 }}
                  animate={{ opacity: 1 }}
                  transition={{ duration: 0.5, delay: 1.8 }}
                />
                
                {/* Chimney */}
                <motion.rect
                  x="200"
                  y="100"
                  width="30"
                  height="50"
                  fill="#5b3e31"
                  stroke="#ffffff"
                  strokeWidth="2"
                  initial={{ opacity: 0 }}
                  animate={{ opacity: 1 }}
                  transition={{ duration: 0.5, delay: 2 }}
                />
              </motion.svg>
              
              {/* Brand Text Inside House */}
              <motion.div
                className="absolute inset-0 flex items-center justify-center"
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                transition={{ duration: 1, delay: 2.2 }}
              >
                <div className="text-center">
                  <h1 className="text-3xl md:text-4xl font-bold text-[#5b3e31] brand-title tracking-wider">
                    MM SPACES
                  </h1>
                  <motion.div
                    className="w-16 h-1 bg-[#5b3e31] mt-2 mx-auto"
                    initial={{ width: 0 }}
                    animate={{ width: 64 }}
                    transition={{ duration: 0.8, delay: 2.5 }}
                  />
                </div>
              </motion.div>
              
              {/* Floating Particles Around House */}
              {[...Array(6)].map((_, i) => (
                <motion.div
                  key={i}
                  className="absolute w-2 h-2 bg-white rounded-full"
                  style={{
                    left: `${Math.random() * 300}px`,
                    top: `${Math.random() * 300}px`,
                  }}
                  animate={{
                    y: [0, -30, 0],
                    opacity: [0, 1, 0],
                    scale: [0, 1, 0],
                  }}
                  transition={{
                    duration: 2 + Math.random() * 2,
                    repeat: Infinity,
                    delay: Math.random() * 2,
                  }}
                />
              ))}
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>

      {/* Main Hero Content */}
      <motion.section 
        id="home" 
        className="relative min-h-screen flex items-center justify-center overflow-hidden bg-gradient-to-br from-white via-[#f5f5f0] to-white"
        initial={{ opacity: 0, y: "100vh" }}
        animate={{ 
          opacity: isLoading ? 0 : 1,
          y: isLoading ? "100vh" : 0,
          transition: { 
            duration: 1.5, 
            ease: [0.25, 0.46, 0.45, 0.94],
            delay: isLoading ? 0.5 : 0
          }
        }}
      >
        {/* Interactive Background */}
        <div className="absolute inset-0">
          {/* Mouse-following gradient */}
          <motion.div
            className="absolute w-96 h-96 rounded-full bg-gradient-to-r from-[#5b3e31]/10 to-[#3d3b3a]/10 blur-3xl"
            animate={{
              x: mousePosition.x - 192,
              y: mousePosition.y - 192,
            }}
            transition={{ type: "spring", stiffness: 100, damping: 30 }}
          />
          
          {/* Floating geometric shapes */}
          {[...Array(8)].map((_, i) => (
            <motion.div
              key={i}
              className="absolute"
              style={{
                left: `${Math.random() * 100}%`,
                top: `${Math.random() * 100}%`,
              }}
              initial={{ 
                opacity: 0,
                scale: 0,
                rotate: Math.random() * 360
              }}
              animate={{
                opacity: [0, 0.1, 0.1, 0],
                scale: [0, 1, 1.5, 0],
                rotate: [0, 180, 360],
                x: [0, Math.random() * 200 - 100, Math.random() * 200 - 100, 0],
                y: [0, Math.random() * 200 - 100, Math.random() * 200 - 100, 0],
              }}
              transition={{
                duration: 8 + Math.random() * 4,
                repeat: Infinity,
                ease: "easeInOut",
                delay: Math.random() * 2,
              }}
            >
              <div className="w-20 h-20 border-2 border-[#5b3e31]/20 rounded-lg" />
            </motion.div>
          ))}
          
          {/* Floating design tools */}
          <motion.div
            className="absolute top-20 left-10 opacity-10"
            animate={{
              rotate: [0, 360],
              y: [0, -30, 0],
              scale: [1, 1.2, 1],
            }}
            transition={{
              duration: 20,
              repeat: Infinity,
              ease: "linear"
            }}
          >
            <div className="design-element">
              <svg viewBox="0 0 24 24">
                <path d="M3 3l7.07 16.97 2.51-7.39 7.39-2.51L3 3m10 10l-3 3" />
              </svg>
            </div>
          </motion.div>
          
          <motion.div
            className="absolute top-40 right-20 opacity-10"
            animate={{
              rotate: [0, -360],
              y: [0, 30, 0],
              scale: [1, 0.8, 1],
            }}
            transition={{
              duration: 25,
              repeat: Infinity,
              ease: "linear"
            }}
          >
            <div className="design-element">
              <svg viewBox="0 0 24 24">
                <rect x="3" y="3" width="18" height="18" rx="2" />
                <line x1="9" y1="3" x2="9" y2="21" />
                <line x1="15" y1="3" x2="15" y2="21" />
                <line x1="3" y1="9" x2="21" y2="9" />
                <line x1="3" y1="15" x2="21" y2="15" />
              </svg>
            </div>
          </motion.div>
          
          <motion.div
            className="absolute bottom-40 left-20 opacity-10"
            animate={{
              rotate: [0, 180],
              x: [0, 50, 0],
              scale: [1, 1.3, 1],
            }}
            transition={{
              duration: 15,
              repeat: Infinity,
              ease: "easeInOut"
            }}
          >
            <div className="design-element">
              <svg viewBox="0 0 24 24">
                <path d="M12 2l3.09 6.26L22 9.27l-5 4.87 1.18 6.88L12 17.77l-6.18 3.25L7 14.14 2 9.27l6.91-1.01L12 2z" />
              </svg>
            </div>
          </motion.div>
          
          {/* Room outline sketch */}
          <motion.svg
            className="absolute bottom-20 right-10 w-64 h-64 opacity-5"
            viewBox="0 0 200 200"
            initial={{ pathLength: 0 }}
            animate={{ pathLength: 1 }}
            transition={{ duration: 3, delay: 2 }}
          >
            <motion.rect
              x="20" y="20" width="160" height="160"
              stroke="#5b3e31"
              strokeWidth="2"
              fill="none"
            />
            <motion.line
              x1="20" y1="100" x2="180" y2="100"
              stroke="#5b3e31"
              strokeWidth="1"
              fill="none"
            />
            <motion.rect
              x="40" y="40" width="60" height="60"
              stroke="#5b3e31"
              strokeWidth="1"
              fill="none"
            />
            <motion.rect
              x="120" y="40" width="40" height="60"
              stroke="#5b3e31"
              strokeWidth="1"
              fill="none"
            />
          </motion.svg>
        </div>

        {/* Main Content */}
        <div className="relative z-10 container mx-auto px-6 text-center">
          <motion.div
            initial={{ scale: 0, rotate: -180 }}
            animate={{ 
              scale: [0, 1.2, 1],
              rotate: [-180, 360, 0],
              transition: { 
                duration: 1.5, 
                delay: isLoading ? 2.5 : 0.5,
                ease: "easeInOut"
              }
            }}
            className="mb-8"
          >
            <Logo size="large" />
          </motion.div>

          <motion.h1
            className="text-5xl md:text-8xl font-bold mb-6 brand-title"
            initial={{ 
              opacity: 0, 
              x: -200, 
              rotateY: 90,
              scale: 0.5
            }}
            animate={{ 
              opacity: 1, 
              x: 0, 
              rotateY: 0,
              scale: 1,
              transition: { 
                duration: 1.5, 
                delay: isLoading ? 3 : 1,
                type: "spring",
                stiffness: 100,
                damping: 20
              }
            }}
          >
            <motion.span 
              className="gradient-text inline-block"
              whileHover={{ 
                scale: 1.05,
                textShadow: "0 0 50px rgba(91, 62, 49, 0.8)",
                transition: { duration: 0.3 }
              }}
            >
              {Array.from("MM Spaces").map((letter, index) => (
                <motion.span
                  key={index}
                  initial={{ 
                    opacity: 0, 
                    y: 100, 
                    rotateZ: Math.random() * 360 - 180,
                    scale: 0
                  }}
                  animate={{ 
                    opacity: 1, 
                    y: 0, 
                    rotateZ: 0,
                    scale: 1,
                    transition: {
                      duration: 1,
                      delay: (isLoading ? 3 : 1) + index * 0.15,
                      type: "spring",
                      stiffness: 300,
                      damping: 25
                    }
                  }}
                  whileHover={{
                    scale: 1.3,
                    color: "#5b3e31",
                    rotateZ: [0, -10, 10, 0],
                    transition: { duration: 0.3 }
                  }}
                >
                  {letter === " " ? "\u00A0" : letter}
                </motion.span>
              ))}
            </motion.span>
          </motion.h1>

          <motion.h2
            className="text-2xl md:text-4xl font-light mb-8 text-[#3d3b3a] brand-elegant"
            initial={{ 
              opacity: 0, 
              x: 100, 
              skewX: 45,
              scale: 0.5
            }}
            animate={{ 
              opacity: 1, 
              x: 0, 
              skewX: 0,
              scale: 1,
              transition: { 
                duration: 1.2, 
                delay: isLoading ? 4 : 1.8,
                type: "spring",
                stiffness: 80
              }
            }}
          >
            Interior Design
          </motion.h2>

          <motion.p
            className="text-lg md:text-xl text-[#3d3b3a] mb-12 max-w-2xl mx-auto brand-elegant"
            initial={{ 
              opacity: 0, 
              scale: 0, 
              rotate: 720,
              y: 100
            }}
            animate={{ 
              opacity: 1, 
              scale: 1, 
              rotate: 0,
              y: 0,
              transition: { 
                duration: 2, 
                delay: isLoading ? 4.5 : 2.2,
                type: "spring",
                stiffness: 60,
                damping: 15
              }
            }}
          >
            Design that inspire
          </motion.p>

          <motion.div
            className="flex flex-col sm:flex-row gap-4 justify-center items-center"
            initial={{ 
              opacity: 0, 
              y: 100,
              scale: 0.5
            }}
            animate={{ 
              opacity: 1, 
              y: 0,
              scale: 1,
              transition: { 
                duration: 1.2, 
                delay: isLoading ? 5 : 2.5,
                type: "spring",
                stiffness: 100
              }
            }}
          >
            <motion.a
              href="#services"
              className="px-8 py-4 bg-gradient-to-r from-[#5b3e31] to-[#000000] text-[#ffffff] rounded-full font-semibold hover:shadow-lg hover:shadow-[#5b3e31]/25 transition-all duration-300"
              whileHover={{ 
                scale: 1.1,
                rotate: [0, 5, -5, 0],
                transition: { duration: 0.3 }
              }}
              whileTap={{ scale: 0.95 }}
            >
              Explore Our Work
            </motion.a>
            
            <motion.a
              href="#contact"
              className="px-8 py-4 border border-[#3d3b3a] text-[#3d3b3a] rounded-full font-semibold hover:bg-[#5b3e31] hover:text-[#ffffff] transition-all duration-300"
              whileHover={{ 
                scale: 1.1,
                rotate: [0, -5, 5, 0],
                transition: { duration: 0.3 }
              }}
              whileTap={{ scale: 0.95 }}
            >
              Get In Touch
            </motion.a>
          </motion.div>

          <motion.div
            className="absolute bottom-8 left-1/2 transform -translate-x-1/2"
            animate={{ 
              y: [0, 15, 0],
              opacity: [0.3, 1, 0.3]
            }}
            transition={{ 
              duration: 2, 
              repeat: Infinity, 
              ease: "easeInOut",
              delay: isLoading ? 6 : 3
            }}
          >
            <svg className="w-6 h-6 text-[#3d3b3a]" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 14l-7 7m0 0l-7-7m7 7V3" />
            </svg>
          </motion.div>
        </div>
      </motion.section>
    </>
  );
};

export default Hero;
